#### Solution A(b) — PHP Server-Side Validation (7 marks)

**File: `process.php`**

```php
<?php
if ($_SERVER["REQUEST_METHOD"] !== "POST") {
    die("Invalid access");
}

$name     = trim($_POST['name']     ?? '');
$email    = trim($_POST['email']    ?? '');
$age      = trim($_POST['age']      ?? '');
$password = $_POST['password']      ?? '';

$errors = [];

// Name
if (empty($name)) {
    $errors[] = "Name is required";
} elseif (!preg_match("/^[A-Za-z ]{2,50}$/", $name)) {
    $errors[] = "Name must contain only letters";
}

// Email
if (empty($email)) {
    $errors[] = "Email is required";
} elseif (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
    $errors[] = "Invalid email format";
}

// Age
if (!is_numeric($age)) {
    $errors[] = "Age must be numeric";
} elseif ($age < 18 || $age > 60) {
    $errors[] = "Age must be between 18 and 60";
}

// Password
if (strlen($password) < 8) {
    $errors[] = "Password must be at least 8 characters";
}

// Output
if (empty($errors)) {
    echo "<h2 style='color:green;'>Registration Successful!</h2>";
    echo "Name: " . htmlspecialchars($name) . "<br>";
    echo "Email: " . htmlspecialchars($email) . "<br>";
    echo "Age: " . htmlspecialchars($age) . "<br>";
} else {
    echo "<h2 style='color:red;'>Errors:</h2><ul>";
    foreach ($errors as $e) {
        echo "<li>" . htmlspecialchars($e) . "</li>";
    }
    echo "</ul>";
}
?>
```

