#### Step 3 — Create `script.js` (Client-Side Validation)

```javascript
// script.js
function validateForm() {
    let name  = document.forms["regForm"]["name"].value.trim();
    let email = document.forms["regForm"]["email"].value.trim();
    let pass  = document.forms["regForm"]["pass"].value;

    // Remove any previous error messages
    document.querySelectorAll('.error').forEach(e => e.remove());

    let isValid = true;

    // 1. Name validation
    if (name === "") {
        showError("name", "Name cannot be empty");
        isValid = false;
    } else if (name.length < 3) {
        showError("name", "Name must be at least 3 characters");
        isValid = false;
    }

    // 2. Email validation (regex)
    let emailPattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (email === "") {
        showError("email", "Email cannot be empty");
        isValid = false;
    } else if (!emailPattern.test(email)) {
        showError("email", "Invalid email format");
        isValid = false;
    }

    // 3. Password validation
    if (pass === "") {
        showError("pass", "Password cannot be empty");
        isValid = false;
    } else if (pass.length < 6) {
        showError("pass", "Password must be at least 6 characters");
        isValid = false;
    }

    return isValid;   // false → form will NOT submit
}

function showError(fieldId, message) {
    let field = document.getElementById(fieldId);
    let span  = document.createElement('span');
    span.className = 'error';
    span.textContent = message;
    field.parentNode.insertBefore(span, field.nextSibling);
}
```

#### Step 4 — Create `process.php` (Server-Side Handler)

```php
<?php
// process.php
if ($_SERVER['REQUEST_METHOD'] !== 'POST') {
    header('Location: index.php');
    exit();
}

// 1. Sanitize input (NEVER trust client data)
$name  = htmlspecialchars(trim($_POST['name']  ?? ''));
$email = filter_var(trim($_POST['email'] ?? ''), FILTER_SANITIZE_EMAIL);
$pass  = $_POST['pass'] ?? '';

// 2. Server-side re-validation (CRITICAL!)
$errors = [];
if (strlen($name) < 3)                          $errors[] = "Invalid name";
if (!filter_var($email, FILTER_VALIDATE_EMAIL))  $errors[] = "Invalid email";
if (strlen($pass) < 6)                           $errors[] = "Weak password";

// 3. Branching logic
if (!empty($errors)) {
    echo "<h2>Registration Failed</h2><ul>";
    foreach ($errors as $err) {
        echo "<li>" . htmlspecialchars($err) . "</li>";
    }
    echo "</ul><a href='index.php'>Go Back</a>";
} else {
    // 4. (In a real lab, save to MySQL here)
    echo "<h2>Welcome, " . $name . "!</h2>";
    echo "<p>Your email <b>" . $email . "</b> has been registered.</p>";
}
?>
```

