#### Model Solution to Q.A(b) — JavaScript Form Validation (7 marks)

```html
<!DOCTYPE html>
<html>
<head>
    <title>Registration</title>
    <style>
        .err { color: red; font-size: 12px; }
    </style>
</head>
<body>
<form name="regForm" action="process.php" method="post" 
      onsubmit="return validate()">

    Name: <input type="text" id="name"><span id="e1"></span><br><br>
    Email: <input type="text" id="email"><span id="e2"></span><br><br>
    Password: <input type="password" id="pass"><span id="e3"></span><br><br>
    Confirm: <input type="password" id="cpass"><span id="e4"></span><br><br>
    Phone: <input type="text" id="phone"><span id="e5"></span><br><br>

    <button type="submit">Register</button>
</form>

<script>
function validate() {
    let ok = true;

    // Clear previous errors
    document.getElementById("e1").innerHTML = "";
    document.getElementById("e2").innerHTML = "";
    document.getElementById("e3").innerHTML = "";
    document.getElementById("e4").innerHTML = "";
    document.getElementById("e5").innerHTML = "";

    let name  = document.getElementById("name").value.trim();
    let email = document.getElementById("email").value.trim();
    let pass  = document.getElementById("pass").value;
    let cpass = document.getElementById("cpass").value;
    let phone = document.getElementById("phone").value.trim();

    // Name
    if (name === "" || name.length < 3) {
        document.getElementById("e1").innerHTML = "Enter valid name (min 3 chars)";
        ok = false;
    }

    // Email
    let emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRe.test(email)) {
        document.getElementById("e2").innerHTML = "Invalid email";
        ok = false;
    }

    // Password
    if (pass.length < 6) {
        document.getElementById("e3").innerHTML = "Password min 6 chars";
        ok = false;
    }

    // Confirm password
    if (pass !== cpass) {
        document.getElementById("e4").innerHTML = "Passwords do not match";
        ok = false;
    }

    // Phone (10 digits)
    let phoneRe = /^[0-9]{10}$/;
    if (!phoneRe.test(phone)) {
        document.getElementById("e5").innerHTML = "Phone must be 10 digits";
        ok = false;
    }

    return ok;
}
</script>
</body>
</html>
```

**Step-by-step logic explanation:**

1. `onsubmit="return validate()"` — The `return` keyword is **critical**: if `validate()` returns `false`, the form does **not** submit. If `true`, the form submits to `process.php`.
2. The function clears all previous error spans (lines `document.getElementById("e...").innerHTML = "";`).
3. `.trim()` removes leading/trailing whitespace.
4. `emailRe` and `phoneRe` are **regular expressions** (regex) — a compact pattern-matching language.
5. The boolean flag `ok` is set to `false` if *any* check fails; returning `ok` at the end blocks submission.

> [!NOTE]
> **Mark Allocation:** 1 mark HTML form, 1 mark JS function skeleton, 1 mark regex, 1 mark all 5 fields, 1 mark error display, 1 mark return logic, 1 mark clean code/comments.

